#include <WiFi.h>
#include <WebServer.h>
#include <ArduinoJson.h>
#include <EEPROM.h>

// WiFi Configuration
const char* ssid = "{{.ssid}}";
const char* password = "{{.password}}";

// Relay Pins
const int relayPins[4] = {{.relay1Pin}, {{.relay2Pin}, {{.relay3Pin}, {{.relay4Pin}}};
const char* relayNames[4] = {"{{.relay1Name}}", "{{.relay2Name}}", "{{.relay3Name}}", "{{.relay4Name}}"};

// Configuration
const char* deviceName = "{{.deviceName}}";
const int autoOffDelay = {{.autoOffDelay}}; // minutes, 0 = disabled
const bool enableScheduler = {{.enableScheduler}};

// Global variables
WebServer server(80);
bool relayStates[4] = {false, false, false, false};
unsigned long relayOnTime[4] = {0, 0, 0, 0};
String deviceIP = "";

// EEPROM addresses
#define EEPROM_SIZE 64
#define RELAY_STATE_ADDR 0
#define AUTO_OFF_DELAY_ADDR 4

// Function prototypes
void setupWiFi();
void setupWebServer();
void handleRoot();
void handleRelayControl();
void handleStatus();
void handleConfig();
void handleReset();
void updateRelay(int relayNum, bool state);
void checkAutoOff();
void loadSettings();
void saveSettings();
String getHTMLHeader();
String getHTMLFooter();
String getRelayCard(int relayNum);

void setup() {
  Serial.begin(115200);
  Serial.println("4-Channel Relay Controller Starting...");

  // Initialize relay pins
  for (int i = 0; i < 4; i++) {
    pinMode(relayPins[i], OUTPUT);
    digitalWrite(relayPins[i], LOW); // Relays are active LOW
  }

  // Initialize EEPROM
  EEPROM.begin(EEPROM_SIZE);
  loadSettings();

  // Setup WiFi
  setupWiFi();

  // Setup web server
  setupWebServer();

  Serial.print("Web server started! IP: ");
  Serial.println(WiFi.localIP());
  deviceIP = WiFi.localIP().toString();
}

void loop() {
  server.handleClient();
  checkAutoOff();
  delay(10);
}

void setupWiFi() {
  Serial.println("Connecting to WiFi...");

  WiFi.begin(ssid, password);

  int attempts = 0;
  while (WiFi.status() != WL_CONNECTED && attempts < 20) {
    delay(500);
    Serial.print(".");
    attempts++;
  }

  if (WiFi.status() == WL_CONNECTED) {
    Serial.println("");
    Serial.println("WiFi connected!");
    Serial.print("IP address: ");
    Serial.println(WiFi.localIP());
  } else {
    Serial.println("Failed to connect to WiFi");
  }
}

void setupWebServer() {
  server.on("/", HTTP_GET, handleRoot);
  server.on("/relay", HTTP_POST, handleRelayControl);
  server.on("/status", HTTP_GET, handleStatus);
  server.on("/config", HTTP_POST, handleConfig);
  server.on("/reset", HTTP_POST, handleReset);

  // Serve static CSS and JS
  server.on("/style.css", []() {
    server.send(200, "text/css", getCSS());
  });

  server.on("/script.js", []() {
    server.send(200, "application/javascript", getJavaScript());
  });

  server.begin();
}

void handleRoot() {
  String html = getHTMLHeader();

  html += "<div class='container'>";
  html += "<h1>" + String(deviceName) + "</h1>";
  html += "<p class='status'>Device IP: " + deviceIP + "</p>";

  // Relay control cards
  for (int i = 0; i < 4; i++) {
    html += getRelayCard(i);
  }

  html += "</div>";
  html += getHTMLFooter();

  server.send(200, "text/html", html);
}

void handleRelayControl() {
  String relayNum = server.arg("relay");
  String state = server.arg("state");

  if (relayNum.length() > 0 && state.length() > 0) {
    int relay = relayNum.toInt();
    bool turnOn = (state == "on");

    if (relay >= 0 && relay < 4) {
      updateRelay(relay, turnOn);

      // Send JSON response
      StaticJsonDocument<200> doc;
      doc["success"] = true;
      doc["relay"] = relay;
      doc["state"] = turnOn;
      doc["name"] = relayNames[relay];

      String response;
      serializeJson(doc, response);
      server.send(200, "application/json", response);

      return;
    }
  }

  // Error response
  StaticJsonDocument<100> doc;
  doc["success"] = false;
  doc["error"] = "Invalid parameters";

  String response;
  serializeJson(doc, response);
  server.send(400, "application/json", response);
}

void handleStatus() {
  StaticJsonDocument<300> doc;
  doc["deviceName"] = deviceName;
  doc["ip"] = deviceIP;
  doc["uptime"] = millis();

  JsonArray relays = doc.createNestedArray("relays");
  for (int i = 0; i < 4; i++) {
    JsonObject relay = relays.createNestedObject();
    relay["id"] = i;
    relay["name"] = relayNames[i];
    relay["state"] = relayStates[i];
    relay["onTime"] = relayOnTime[i];
  }

  String response;
  serializeJson(doc, response);
  server.send(200, "application/json", response);
}

void handleConfig() {
  // Handle configuration updates
  String response = "{\"success\":true,\"message\":\"Configuration updated\"}";
  server.send(200, "application/json", response);
}

void handleReset() {
  // Reset all relays to OFF
  for (int i = 0; i < 4; i++) {
    updateRelay(i, false);
  }

  String response = "{\"success\":true,\"message\":\"All relays reset\"}";
  server.send(200, "application/json", response);
}

void updateRelay(int relayNum, bool state) {
  if (relayNum < 0 || relayNum >= 4) return;

  relayStates[relayNum] = state;

  // Relays are active LOW
  digitalWrite(relayPins[relayNum], state ? LOW : HIGH);

  if (state) {
    relayOnTime[relayNum] = millis();
    Serial.print("Relay ");
    Serial.print(relayNum + 1);
    Serial.print(" (");
    Serial.print(relayNames[relayNum]);
    Serial.println(") turned ON");
  } else {
    relayOnTime[relayNum] = 0;
    Serial.print("Relay ");
    Serial.print(relayNum + 1);
    Serial.print(" (");
    Serial.print(relayNames[relayNum]);
    Serial.println(") turned OFF");
  }

  // Save state to EEPROM
  saveSettings();
}

void checkAutoOff() {
  if (autoOffDelay <= 0) return; // Auto-off disabled

  unsigned long currentTime = millis();
  unsigned long delayMs = autoOffDelay * 60 * 1000UL; // Convert minutes to milliseconds

  for (int i = 0; i < 4; i++) {
    if (relayStates[i] && (currentTime - relayOnTime[i] >= delayMs)) {
      Serial.print("Auto-off: Relay ");
      Serial.print(i + 1);
      Serial.println(" turned off due to time limit");
      updateRelay(i, false);
    }
  }
}

void loadSettings() {
  // Load relay states from EEPROM
  for (int i = 0; i < 4; i++) {
    relayStates[i] = EEPROM.read(EEPROM_STATE_ADDR + i);
    if (relayStates[i]) {
      digitalWrite(relayPins[i], LOW); // Turn on if saved state is ON
      relayOnTime[i] = millis();
    }
  }

  // Load auto-off delay
  // Note: This would need multi-byte storage for larger values
  // For simplicity, using 0-255 minute range
  int savedDelay = EEPROM.read(AUTO_OFF_DELAY_ADDR);
  if (savedDelay > 0 && savedDelay <= 255) {
    // Use saved value if valid
  }
}

void saveSettings() {
  // Save relay states to EEPROM
  for (int i = 0; i < 4; i++) {
    EEPROM.write(EEPROM_STATE_ADDR + i, relayStates[i]);
  }

  // Save auto-off delay
  EEPROM.write(AUTO_OFF_DELAY_ADDR, (autoOffDelay <= 255) ? autoOffDelay : 0);

  EEPROM.commit();
}

String getHTMLHeader() {
  return R"(<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>)" + String(deviceName) + R"(</title>
    <link rel="stylesheet" href="/style.css">
</head>
<body>)";
}

String getHTMLFooter() {
  return R"(</body>
<script src="/script.js"></script>
</html>)";
}

String getRelayCard(int relayNum) {
  String card = R"(<div class="relay-card">)";
  card += "<h2>" + String(relayNames[relayNum]) + "</h2>";
  card += "<div class="relay-status" id="status-" + String(relayNum) + "">";
  card += "<span class="status-text">" + String(relayStates[relayNum] ? "ON" : "OFF") + "</span>";
  card += "</div>";
  card += "<div class="relay-controls">";
  card += "<button class=\"btn btn-on\" onclick=\"toggleRelay(" + String(relayNum) + ", true)\">ON</button>";
  card += "<button class=\"btn btn-off\" onclick=\"toggleRelay(" + String(relayNum) + ", false)\">OFF</button>";
  card += "</div>";
  card += "</div>";
  return card;
}

String getCSS() {
  return R"(* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    color: #333;
  }

  .container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
  }

  h1 {
    text-align: center;
    color: white;
    margin-bottom: 10px;
    text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
  }

  .status {
    text-align: center;
    color: white;
    margin-bottom: 30px;
    font-size: 14px;
  }

  .relay-card {
    background: white;
    border-radius: 15px;
    padding: 25px;
    margin-bottom: 20px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.1);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
  }

  .relay-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0,0,0,0.15);
  }

  .relay-card h2 {
    margin: 0 0 15px 0;
    color: #333;
    font-size: 1.4em;
  }

  .relay-status {
    margin-bottom: 20px;
  }

  .status-text {
    font-size: 1.2em;
    font-weight: bold;
    padding: 8px 16px;
    border-radius: 20px;
    display: inline-block;
  }

  .status-text:contains("ON") {
    background: #4CAF50;
    color: white;
  }

  .status-text:contains("OFF") {
    background: #f44336;
    color: white;
  }

  .relay-controls {
    display: flex;
    gap: 15px;
  }

  .btn {
    flex: 1;
    padding: 12px 20px;
    border: none;
    border-radius: 8px;
    font-size: 16px;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.3s ease;
    text-transform: uppercase;
  }

  .btn-on {
    background: #4CAF50;
    color: white;
  }

  .btn-on:hover {
    background: #45a049;
    transform: scale(1.05);
  }

  .btn-off {
    background: #f44336;
    color: white;
  }

  .btn-off:hover {
    background: #da190b;
    transform: scale(1.05);
  })";
}

String getJavaScript() {
  return R"(function toggleRelay(relayNum, state) {
  fetch('/relay', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: 'relay=' + relayNum + '&state=' + (state ? 'on' : 'off')
  })
  .then(response => response.json())
  .then(data => {
    if (data.success) {
      updateStatus(data.relay, data.state);
    } else {
      console.error('Error:', data.error);
    }
  })
  .catch(error => console.error('Error:', error));
}

function updateStatus(relayNum, state) {
  const statusElement = document.getElementById('status-' + relayNum);
  const statusText = statusElement.querySelector('.status-text');

  statusText.textContent = state ? 'ON' : 'OFF';

  if (state) {
    statusText.style.background = '#4CAF50';
  } else {
    statusText.style.background = '#f44336';
  }
}

// Auto-refresh status every 5 seconds
setInterval(() => {
  fetch('/status')
    .then(response => response.json())
    .then(data => {
      data.relays.forEach(relay => {
        updateStatus(relay.id, relay.state);
      });
    })
    .catch(error => console.error('Status update error:', error));
}, 5000);)";
}
